mapper.select:
SELECT lr.id, lr.phone, lr.name, lr.older_name AS olderName, lr.type, lr.appointment_time AS appointmentTime, lr.status, lr.visit_time AS visitTime, ( SELECT lem.greeting FROM lc_elder_member lem JOIN elder e ON e.id = lem.elder_id WHERE lem.member_id = lr.member_id AND ( lr.older_name = e.name OR lr.older_name IS NULL ) LIMIT 1 ) AS greeting FROM lc_reservation lr
lr.member_id = #{memberId}
AND lr.`status` = #{status}
order by lr.appointment_time desc
